---
import type { HTMLAttributes } from "astro/types"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"aside"> &
  VariantProps<typeof variants> & {
    storageKey?: string
  }

const variants = cva("relative flex min-h-12 items-center py-2", {
  variants: {
    variant: {
      default: "bg-foreground text-background w-full",
      floating:
        "bg-background text-foreground border-border mx-auto my-2 w-[calc(100%-3rem)] max-w-container overflow-hidden rounded-xl border shadow-sm",
    },
  },
  defaultVariants: {
    variant: "default",
  },
})

const {
  class: className,
  variant,
  storageKey,
  ...props
} = Astro.props
---

<aside
  class={cn(variants({ variant }), className)}
  data-slot="banner"
  data-banner-storage-key={storageKey}
  data-variant={variant}
  {...props}
>
  <slot />
</aside>

<script is:inline>
  const initializedKey = "fulldevBannerInitialized"

  if (!document.documentElement.dataset[initializedKey]) {
    document.documentElement.dataset[initializedKey] = "true"

    const getStorageToken = (key) => `banner:${key}`

    const syncBanners = () => {
      document.querySelectorAll("[data-slot='banner']").forEach((banner) => {
        if (!(banner instanceof HTMLElement)) return

        const storageKey = banner.dataset.bannerStorageKey

        if (
          storageKey &&
          sessionStorage.getItem(getStorageToken(storageKey)) === "hidden"
        ) {
          banner.hidden = true
        }
      })
    }

    syncBanners()

    document.addEventListener("click", (event) => {
      const target = event.target

      if (!(target instanceof Element)) return

      const closeButton = target.closest("[data-slot='banner-close']")

      if (!(closeButton instanceof HTMLElement)) return

      const banner = closeButton.closest("[data-slot='banner']")

      if (!(banner instanceof HTMLElement)) return

      banner.hidden = true

      const storageKey = banner.dataset.bannerStorageKey

      if (storageKey) {
        sessionStorage.setItem(getStorageToken(storageKey), "hidden")
      }
    })
  }
</script>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

import BannerClose from "./banner-close.astro"

type Props = HTMLAttributes<"div"> & {
  showClose?: boolean
}

const { class: className, showClose = true, ...props } = Astro.props
---

<div
  class={cn(
    "relative mx-auto flex w-full max-w-container flex-col gap-2 px-6 pr-10 in-[[data-slot=sidebar-inset]]:px-4 in-[[data-slot=sidebar-inset]]:pr-8 @5xl:flex-row @5xl:items-center",
    className
  )}
  {...props}
>
  <slot />
  {
    showClose && (
      <BannerClose
        class="absolute top-1/2 right-4 z-20 -translate-y-1/2 in-[[data-variant=floating]]:right-5"
        aria-label="Close"
      />
    )
  }
</div>
